import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

// API adresimizi bir değişkene atıyoruz (Port 5000'de çalıştığından emin ol)
const API_BASE_URL = 'http://127.0.0.1:5000/api';

function App() {
  // Verileri saklayacağımız state (durum) yapısı
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  // Sayfa açıldığında API'den veriyi çeken fonksiyon
  useEffect(() => {
    axios.get(`${API_BASE_URL}/kpi/summary`)
      .then(res => {
        setData(res.data);
        setLoading(false);
      })
      .catch(err => {
        console.error("Veri çekme hatası:", err);
        setLoading(false);
      });
  }, []);

  // Veriler yüklenirken gösterilecek alan
  if (loading) return <div style={{textAlign: 'center', padding: '50px'}}><h2>Veriler Yükleniyor...</h2></div>;

  return (
    <div className="App">
      <div className="dashboard-container">
        {/* 1. Başlık Alanı */}
        <header className="header">
          <h1>📊 InsightFlow KDS: E-Ticaret Performans Panosu</h1>
          <p style={{color: '#666'}}>Canlı Veritabanı Bağlantısı: Aktif ✅</p>
        </header>

        {/* 2. KPI Kartları Alanı (API'den gelen verilerle doluyor) */}
        <div className="kpi-cards" style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '30px' }}>
          <div style={cardStyle}>
            <span style={labelStyle}>Toplam Ciro</span>
            <div style={valueStyle}>₺{data?.total_revenue.toLocaleString()}</div>
          </div>
          <div style={cardStyle}>
            <span style={labelStyle}>Dönüşüm Oranı</span>
            <div style={valueStyle}>%{data?.conversion_rate}</div>
          </div>
          <div style={cardStyle}>
            <span style={labelStyle}>Müşteri Sayısı</span>
            <div style={valueStyle}>{data?.unique_customers}</div>
          </div>
          <div style={cardStyle}>
            <span style={labelStyle}>Ort. Sipariş Değeri</span>
            <div style={valueStyle}>₺{data?.aov.toFixed(2)}</div>
          </div>
        </div>

        {/* 3. Grafik Alanı */}
        <div className="charts-area" style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '20px' }}>
          <div style={{...chartStyle, height: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
             <p style={{color: '#ccc'}}>Gelir Trend Grafiği Yakında (Aşama 4)</p>
          </div>
          <div style={{...chartStyle, height: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center'}}>
             <p style={{color: '#ccc'}}>Kategori Dağılımı Yakında (Aşama 4)</p>
          </div>
        </div>

        {/* 4. Detay Tablolar Alanı */}
        <div className="details-area" style={{ marginTop: '30px', padding: '20px', borderTop: '1px solid #ccc' }}>
          <h2>Bölgesel Satış Detayı ve Hedef Takibi</h2>
          <p>Toplam İşlenen Sipariş: <strong>{data?.total_orders}</strong></p>
        </div>

      </div>
    </div>
  );
}

// Stil Tanımlamaları
const cardStyle = {
  flex: 1,
  margin: '0 10px',
  padding: '20px',
  backgroundColor: '#ffffff',
  borderRadius: '8px',
  boxShadow: '0 4px 8px rgba(0,0,0,0.1)',
  textAlign: 'center'
};

const labelStyle = {
  fontSize: '0.8em',
  color: '#888',
  textTransform: 'uppercase',
  display: 'block',
  marginBottom: '5px'
};

const valueStyle = {
  fontSize: '1.5em',
  fontWeight: 'bold',
  color: '#333'
};

const chartStyle = {
  backgroundColor: '#ffffff',
  padding: '20px',
  borderRadius: '8px',
  boxShadow: '0 4px 8px rgba(0, 0, 0, 0.1)'
};

export default App;
